import{_ as e,c as n,a1 as a,o as h}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Thu thập thông tin sử dụng theHarvester","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/6-theHarvester.md","filePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/6-theHarvester.md"}'),r={name:"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/6-theHarvester.md"};function c(i,t,o,s,u,l){return h(),n("div",null,t[0]||(t[0]=[a('<h1 id="thu-thap-thong-tin-su-dung-theharvester" tabindex="-1">Thu thập thông tin sử dụng theHarvester <a class="header-anchor" href="#thu-thap-thong-tin-su-dung-theharvester" aria-label="Permalink to &quot;Thu thập thông tin sử dụng theHarvester&quot;">​</a></h1><p>theHarvester được sử dụng để thu thập tình báo mã nguồn mở (OSINT) về một công ty hoặc tên miền. theHarvester thu thập email, subdomain, host, tên nhân viên, cổng mở và banner từ các nguồn công khai khác nhau như công cụ tìm kiếm, máy chủ khóa PGP và cơ sở dữ liệu máy tính SHODAN.</p><p><em>Kho lưu trữ chính thức:</em> <a href="https://github.com/laramies/theHarvester" target="_blank" rel="noreferrer">https://github.com/laramies/theHarvester</a></p><h2 id="tong-quan-ve-theharvester" tabindex="-1">Tổng quan về theHarvester <a class="header-anchor" href="#tong-quan-ve-theharvester" aria-label="Permalink to &quot;Tổng quan về theHarvester&quot;">​</a></h2><p>Được phát triển bằng Python bởi Christian Martorella. Đây là công cụ rất hữu ích trong giai đoạn đầu của kiểm thử xâm nhập. Giúp hiểu footprint của khách hàng trên internet. Một số chuyên gia cũng sử dụng theHarvester để xem xét thông tin có sẵn cho kẻ tấn công qua internet.</p><h3 id="yeu-cau" tabindex="-1">Yêu cầu: <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu:&quot;">​</a></h3><ul><li>Máy ảo Kali Linux.</li></ul><h3 id="muc-tieu" tabindex="-1">Mục tiêu: <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu:&quot;">​</a></h3><ul><li>Trình bày cách xác định lỗ hổng và rò rỉ thông tin trên công cụ tìm kiếm sử dụng theHarvester.</li><li>Trích xuất email, tên subdomain, virtual host(...) từ các trang web.</li></ul><hr><h2 id="chay-theharvester-voi-muc-tieu" tabindex="-1">Chạy theHarvester với mục tiêu <a class="header-anchor" href="#chay-theharvester-voi-muc-tieu" aria-label="Permalink to &quot;Chạy theHarvester với mục tiêu&quot;">​</a></h2><p>Để xem tất cả tùy chọn lệnh, gõ:</p><p><code>theHarvester -h</code></p><p>Hãy thực hiện harvest đầy đủ trên mục tiêu này:</p><p><code>theHarvester -d certifiedhacker.com -l 300 -b all</code></p><p>Trong lệnh <code>help</code> bạn có thể thấy ý nghĩa của các tùy chọn này, như <code>-d</code> là tên miền, <code>-l</code> để giới hạn số kết quả tìm kiếm, và <code>-b</code> là công cụ tìm kiếm/nguồn.</p><p>theHarvester có thể trả về quá nhiều thông tin để xem qua, để dễ đọc hơn, bạn có thể ghi output ra file HTML:</p><p><code>theHarvester -d certifiedhacker.com -l 300 -b all -f report</code></p><p>File sẽ được xuất trong thư mục home trên máy Kali.</p><p>Lưu ý: Nếu bạn gặp khó khăn khi xuất file HTML, hãy lưu ý rằng đây là một lượng thông tin rất lớn đang được thu thập, bạn có thể giảm số lượng công cụ tìm kiếm/nguồn, thay vì sử dụng tất cả cùng một lúc.</p>',20)]))}const d=e(r,[["render",c]]);export{m as __pageData,d as default};
